export const TOPICS_B = [
  // ── TK–2 ───────────────────────────────────────────────────────────────────
  { id:'skip-counting-2s-5s', title:'Skip Counting by 2s and 5s', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['skip counting','2s','5s','patterns','number sense'], summary:'Count by 2s and 5s to build number pattern fluency.', intro:'Skip counting is counting by jumps larger than 1. It prepares you for multiplication.', steps:[{title:'Count by 2s',body:'2, 4, 6, 8, 10… always add 2. Even numbers only.'},{title:'Count by 5s',body:'5, 10, 15, 20… always add 5. Ends in 0 or 5.'},{title:'Use a number line',body:'Mark every 2nd or 5th number on the number line to see the jumps.'},{title:'Use arrays',body:'2 rows of objects: count each row = skip by 2. 5 columns: skip by 5.'}], explanation:'Skip counting is repeated addition — the direct foundation of multiplication tables.', exercises:[{question:'Count by 2s from 4 to 14.',answer:'4,6,8,10,12,14',hint:'Add 2 each time.'},{question:'Count by 5s: 5, 10, ___, 20',answer:'15',hint:'Add 5.'},{question:'How many legs on 7 birds?',answer:'14',hint:'Skip count by 2s seven times.'}]},
  { id:'comparing-numbers', title:'Comparing Numbers', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['compare','greater than','less than','equal','symbols'], summary:'Use >, <, = to compare two numbers.', intro:'Comparing numbers tells us which is larger or if they are equal.', steps:[{title:'Learn the symbols',body:'> means greater than. < means less than. = means equal.'},{title:'Use place value',body:'Compare digits from left to right. First different digit decides.'},{title:'Alligator trick',body:'The open mouth always faces the bigger number.'},{title:'Use a number line',body:'Numbers further right are always greater.'}], explanation:'Place value comparison: always start with the highest place digit.', exercises:[{question:'Compare 47 __ 52',answer:'47 < 52',hint:'Tens digit: 4 < 5.'},{question:'Compare 83 __ 83',answer:'83 = 83',hint:'All digits are equal.'},{question:'Order from least to greatest: 29, 17, 41',answer:'17, 29, 41',hint:'Compare tens first.'}]},
  { id:'basic-geometry-solid-shapes', title:'3D Shapes', grade:'tk2', gradeLabel:'TK–2', subject:'geometry', tags:['3D shapes','cube','sphere','cylinder','cone','faces','edges','vertices'], summary:'Identify and describe 3D solid shapes by their faces, edges, and vertices.', intro:'3D shapes have depth — they are not flat. We describe them by faces, edges, and vertices.', steps:[{title:'Key 3D shapes',body:'Cube: 6 square faces. Rectangular prism: 6 faces. Sphere: 0 flat faces. Cylinder: 2 circular bases. Cone: 1 circular base. Pyramid: triangular faces + 1 base.'},{title:'Count faces',body:'Faces are flat surfaces. A cube has 6.'},{title:'Count edges',body:'Edges are where 2 faces meet. Cube: 12.'},{title:'Count vertices',body:'Vertices are corners. Cube: 8.'}], explanation:'Euler\'s formula: Faces + Vertices - Edges = 2 for any convex polyhedron.', exercises:[{question:'How many faces does a cube have?',answer:'6',hint:'Top, bottom, front, back, left, right.'},{question:'Sphere: how many edges?',answer:'0',hint:'No flat faces means no edges.'},{question:'Cone: how many vertices?',answer:'1',hint:'Just the pointed tip.'}]},
  { id:'ordinal-numbers', title:'Ordinal Numbers', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['ordinal','first','second','third','position','order'], summary:'Use ordinal numbers to describe position in a sequence.', intro:'Ordinal numbers tell position: 1st, 2nd, 3rd, 4th…', steps:[{title:'Cardinal vs Ordinal',body:'Cardinal: how many (5 apples). Ordinal: which position (5th place).'},{title:'Spelling pattern',body:'1st, 2nd, 3rd, then -th: 4th, 5th, 6th…'},{title:'Use in context',body:'"The 3rd house on the left." "Finish in 1st place."'}], explanation:'Ordinal numbers are fundamental to ranking, position, and sequencing events.', exercises:[{question:'What position is 4th from the front if there are 10 people?',answer:'4th',hint:'Count 1,2,3,4 from front.'},{question:'Spell the ordinal for 12.',answer:'12th',hint:'Most numbers after 3rd use -th.'},{question:'In a race, you finish 2nd. Who finished before you?',answer:'1 person (the 1st place finisher)',hint:'Ordinal tells position.'}]},
  { id:'calendar-time', title:'Calendar & Days of the Week', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['calendar','days','weeks','months','date','time'], summary:'Read a calendar and understand days, weeks, and months.', intro:'Calendars organize time. Knowing them helps plan ahead.', steps:[{title:'Days of week',body:'Sunday, Monday, Tuesday, Wednesday, Thursday, Friday, Saturday — 7 days = 1 week.'},{title:'Months of year',body:'12 months. January–December. Months have 28–31 days.'},{title:'Reading dates',body:'Month/Day/Year. April 3, 2025 = 4/3/2025.'},{title:'Count days between dates',body:'From April 5 to April 12: count forward: 5→12 = 7 days.'}], explanation:'The Gregorian calendar has 365 days per year, 366 in leap years.', exercises:[{question:'How many days in 2 weeks?',answer:'14 days',hint:'2 × 7 = 14.'},{question:'What month comes after June?',answer:'July',hint:'Count: Jan, Feb… Jun, Jul.'},{question:'If today is Monday, what day is in 3 days?',answer:'Thursday',hint:'Mon → Tue → Wed → Thu.'}]},
  { id:'even-odd-numbers', title:'Even and Odd Numbers', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['even','odd','pairs','two groups'], summary:'Decide if a number is even or odd by checking if it makes equal pairs.', intro:'A number is even if it can be split into equal pairs with nothing left over. Odd numbers have one leftover.', steps:[{title:'Pair objects',body:'Group into pairs. 6 objects → 3 pairs, none left → even.'},{title:'Check the last digit',body:'Even ends in 0,2,4,6,8. Odd ends in 1,3,5,7,9.'},{title:'Even + Even = Even',body:'4+6=10 (even). Odd + Odd = Even. Even + Odd = Odd.'}], explanation:'Even numbers are multiples of 2. Odd numbers are not divisible by 2.', exercises:[{question:'Is 37 even or odd?',answer:'Odd',hint:'Ends in 7.'},{question:'Is the sum 14 + 9 even or odd?',answer:'Odd',hint:'Even + Odd = Odd.'},{question:'List even numbers from 10 to 20.',answer:'10,12,14,16,18,20',hint:'Add 2 each time.'}]},
  { id:'money-basics', title:'Counting Money', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['money','coins','dollars','cents','penny','nickel','dime','quarter'], summary:'Identify coins and count collections of money.', intro:'Coins and bills represent amounts of money. Knowing coin values lets you count any amount.', steps:[{title:'Coin values',body:'Penny=1¢. Nickel=5¢. Dime=10¢. Quarter=25¢. Dollar coin=$1.'},{title:'Count from greatest to least',body:'Start with largest coins first: quarters, then dimes, then nickels, then pennies.'},{title:'Dollar bills',body:'$1, $5, $10, $20, $50, $100. 100 pennies = $1.'},{title:'Make change',body:'Item costs 73¢. You pay $1. Change = 100-73 = 27¢.'}], explanation:'Counting money uses skip counting and place value simultaneously.', exercises:[{question:'2 quarters + 1 dime + 3 pennies = ?',answer:'63¢',hint:'50+10+3=63.'},{question:'$5 - $3.47 = ?',answer:'$1.53',hint:'500-347=153¢.'},{question:'How many nickels equal a quarter?',answer:'5 nickels',hint:'5×5=25.'}]},
  { id:'addition-with-regrouping', title:'Addition with Regrouping', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['addition','regrouping','carrying','two digit'], summary:'Add two-digit numbers by regrouping (carrying) when the ones column exceeds 9.', intro:'When the sum of digits in a column is 10 or more, we regroup into the next place.', steps:[{title:'Add the ones column',body:'27+45: ones: 7+5=12. Write 2 in ones, carry 1 to tens.'},{title:'Add the tens column',body:'Tens: 2+4=6, plus the carried 1 = 7. Write 7 in tens.'},{title:'Result',body:'27+45=72.'},{title:'Check by estimation',body:'27≈30, 45≈45. 30+45=75≈72. Close! ✓'}], explanation:'Regrouping moves extra value into the next higher place. This is the definition of the base-10 system.', exercises:[{question:'38 + 54 = ?',answer:'92',hint:'Ones: 8+4=12, carry 1. Tens: 3+5+1=9.'},{question:'67 + 89 = ?',answer:'156',hint:'Ones: 16, carry. Tens: 6+8+1=15, carry.'}]},
  { id:'subtraction-with-regrouping', title:'Subtraction with Regrouping', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['subtraction','regrouping','borrowing','two digit'], summary:'Subtract two-digit numbers by regrouping (borrowing) when the top digit is smaller.', intro:'When the top digit is smaller than the bottom digit, borrow from the next column.', steps:[{title:'Check ones column',body:'52-28: ones: 2<8, need to borrow.'},{title:'Borrow from tens',body:'Borrow 1 ten (=10 ones) from 5 tens. Now ones: 12-8=4. Tens: 4-2=2.'},{title:'Result',body:'52-28=24.'},{title:'Check',body:'24+28=52 ✓'}], explanation:'Borrowing temporarily reorganizes value across place values without changing the total.', exercises:[{question:'73 - 46 = ?',answer:'27',hint:'Borrow: 13-6=7. 6-4=2.'},{question:'90 - 37 = ?',answer:'53',hint:'Borrow from tens: 10-7=3. 8-3=5.'}]},
  { id:'basic-fractions-halves-quarters', title:'Halves and Quarters', grade:'tk2', gradeLabel:'TK–2', subject:'fractions', tags:['half','quarter','fraction','equal parts'], summary:'Understand and identify one half and one quarter of a whole.', intro:'Half means 2 equal parts. Quarter means 4 equal parts.', steps:[{title:'One half (1/2)',body:'Divide a whole into 2 equal parts. Each part is 1/2.'},{title:'One quarter (1/4)',body:'Divide a whole into 4 equal parts. Each part is 1/4.'},{title:'Compare',body:'1/2 = 2/4. Two quarters make a half.'},{title:'Real examples',body:'Half hour = 30 min. Quarter dollar = 25 cents.'}], explanation:'These are the earliest fractions children encounter. They appear in clocks, money, and cooking.', exercises:[{question:'What is half of 10?',answer:'5',hint:'10 ÷ 2 = 5.'},{question:'How many quarters make a whole?',answer:'4',hint:'4 × 1/4 = 1.'},{question:'Is 1/2 > 1/4?',answer:'Yes',hint:'Same whole, fewer pieces = bigger each.'}]},

  // ── Grades 3–5 ─────────────────────────────────────────────────────────────
  { id:'rounding-numbers', title:'Rounding Numbers', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['rounding','nearest ten','nearest hundred','estimation'], summary:'Round numbers to the nearest ten, hundred, or thousand.', intro:'Rounding gives an approximate number that is easier to work with.', steps:[{title:'Identify the rounding place',body:'Round 347 to nearest ten: look at the ones digit (7).'},{title:'Apply the rule',body:'Digit <5 → round down. Digit ≥5 → round up. 7≥5 → round up: 350.'},{title:'Round to hundreds',body:'347 to nearest hundred: tens digit is 4<5, round down: 300.'},{title:'Estimation',body:'To estimate 47+63: 50+60=110 ≈ 110.'}], explanation:'Rounding introduces the concept of approximation — crucial in science, engineering, and everyday math.', exercises:[{question:'Round 264 to the nearest ten.',answer:'260',hint:'Ones digit 4<5, round down.'},{question:'Round 785 to the nearest hundred.',answer:'800',hint:'Tens digit 8≥5, round up.'},{question:'Estimate 318+472.',answer:'≈800',hint:'300+500=800.'}]},
  { id:'division-intro', title:'Division (Introduction)', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['division','divide','quotient','equal groups','share'], summary:'Divide to split equally or find how many groups.', intro:'Division splits a number into equal groups. It is the inverse of multiplication.', steps:[{title:'Equal sharing',body:'12 ÷ 4 = 3. Share 12 equally among 4 people: each gets 3.'},{title:'Equal grouping',body:'12 ÷ 4 = 3. How many groups of 4 fit in 12? Three groups.'},{title:'Division and multiplication',body:'12 ÷ 4 = ? is the same as ? × 4 = 12.'},{title:'Remainders',body:'13 ÷ 4 = 3 R1. Three groups of 4 with 1 leftover.'}], explanation:'Division is the inverse operation of multiplication. Every division fact relates to a multiplication fact.', exercises:[{question:'24 ÷ 6 = ?',answer:'4',hint:'4 × 6 = 24.'},{question:'17 ÷ 5 = ?',answer:'3 R2',hint:'5×3=15, leftover 2.'},{question:'42 ÷ 7 = ?',answer:'6',hint:'6 × 7 = 42.'}]},
  { id:'geometry-perimeter', title:'Perimeter of Polygons', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['perimeter','polygons','sides','add lengths'], summary:'Find perimeter by adding all side lengths of a shape.', intro:'Perimeter is the total distance around a polygon.', steps:[{title:'List all sides',body:'Triangle with sides 3, 4, 5 cm.'},{title:'Add them up',body:'P = 3+4+5 = 12 cm.'},{title:'Regular shapes shortcut',body:'Regular hexagon side=6: P=6×6=36.'},{title:'Rectangle shortcut',body:'P=2l+2w.'}], explanation:'Perimeter is used for fencing, framing pictures, and measuring borders.', exercises:[{question:'Pentagon with all sides 7cm. Perimeter?',answer:'35 cm',hint:'5×7=35.'},{question:'Triangle with sides 9, 12, 15. Perimeter?',answer:'36 cm',hint:'9+12+15=36.'},{question:'Rectangle 8×3. Perimeter?',answer:'22 cm',hint:'2(8+3)=22.'}]},
  { id:'comparing-fractions', title:'Comparing Fractions', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['compare fractions','greater than','less than','common denominator'], summary:'Compare fractions using common denominators or benchmark fractions.', intro:'To compare fractions they must reference the same whole, split into comparable parts.', steps:[{title:'Same denominator',body:'3/8 vs 5/8: same denominator, compare numerators. 3<5 so 3/8<5/8.'},{title:'Same numerator',body:'2/5 vs 2/7: same numerator, fewer pieces = bigger each. 2/5>2/7.'},{title:'Use benchmarks',body:'Compare to 0, 1/2, 1. 3/8<1/2 since 3<4. 5/8>1/2 since 5>4.'},{title:'Common denominator',body:'1/3 vs 1/4: LCD=12. 4/12 vs 3/12. 4/12>3/12.'}], explanation:'Benchmark fractions (0, 1/4, 1/2, 3/4, 1) allow fast comparison without full calculation.', exercises:[{question:'Compare 3/5 and 4/7.',answer:'3/5 > 4/7',hint:'LCD=35: 21/35 vs 20/35.'},{question:'Which is bigger: 7/8 or 5/6?',answer:'7/8',hint:'LCD=24: 21/24 vs 20/24.'},{question:'Compare 2/3 and 5/8.',answer:'2/3 > 5/8',hint:'LCD=24: 16 vs 15.'}]},
  { id:'geometry-angles-intro', title:'Types of Angles', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['angles','acute','right','obtuse','straight','degree'], summary:'Identify acute, right, obtuse, and straight angles.', intro:'An angle is formed when two rays meet at a vertex. We measure angles in degrees.', steps:[{title:'Right angle',body:'Exactly 90°. Looks like a corner of a square. Symbol: small square.'},{title:'Acute angle',body:'Less than 90°. Sharp, pointed.'},{title:'Obtuse angle',body:'Between 90° and 180°. Wider than a right angle.'},{title:'Straight angle',body:'Exactly 180°. A flat line.'}], explanation:'A protractor measures angles in degrees. Angles are the building blocks of geometry.', exercises:[{question:'Is 75° acute or obtuse?',answer:'Acute',hint:'75 < 90.'},{question:'Is 120° acute or obtuse?',answer:'Obtuse',hint:'90 < 120 < 180.'},{question:'How many right angles in a rectangle?',answer:'4',hint:'All corners are 90°.'}]},
  { id:'properties-of-operations', title:'Properties of Operations', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['commutative','associative','distributive','identity','zero property'], summary:'Use arithmetic properties to simplify calculations.', intro:'Properties are rules that always work for numbers. They speed up calculations.', steps:[{title:'Commutative',body:'a+b=b+a and a×b=b×a. 4+7=7+4. Order does not matter for + and ×.'},{title:'Associative',body:'(a+b)+c=a+(b+c). Grouping does not matter.'},{title:'Distributive',body:'a×(b+c)=a×b+a×c. 3×(4+5)=12+15=27.'},{title:'Identity',body:'a+0=a. a×1=a. Zero for addition, one for multiplication.'}], explanation:'These properties are the axioms of arithmetic — the rules all number systems follow.', exercises:[{question:'Use the distributive property: 6×(10+3)',answer:'78',hint:'6×10+6×3=60+18=78.'},{question:'Is subtraction commutative?',answer:'No',hint:'9-4≠4-9.'},{question:'Simplify: 5+17+5',answer:'27',hint:'Commutative: 5+5+17=27.'}]},
  { id:'decimals-money', title:'Decimals & Money', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['decimals','money','dollars','cents','hundredths'], summary:'Connect decimals to money — dollars and cents.', intro:'Money is the most natural way to understand decimals. $3.47 = 3 dollars and 47 cents.', steps:[{title:'Place values in money',body:'$3.47: 3 is dollars (ones), 4 is dimes (tenths), 7 is pennies (hundredths).'},{title:'Add money',body:'$2.35+$1.48: add cents 35+48=83. Add dollars 2+1=3. Total: $3.83.'},{title:'Subtract money',body:'$5.00-$1.75: 500-175=325 cents = $3.25.'},{title:'Multiply price',body:'3 items at $2.25 each: 3×2.25=$6.75.'}], explanation:'Money is an everyday context for decimals to hundredths — a perfect bridge to abstract decimal operations.', exercises:[{question:'$4.56+$2.87=?',answer:'$7.43',hint:'56+87=143 cents=1.43. 4+2+1=7.'},{question:'$10.00-$6.34=?',answer:'$3.66',hint:'1000-634=366 cents.'},{question:'5 items at $1.35 each?',answer:'$6.75',hint:'5×135=675 cents.'}]},
  { id:'intro-to-geometry-symmetry', title:'Lines of Symmetry', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['symmetry','line of symmetry','reflection','fold'], summary:'Identify and draw lines of symmetry in 2D shapes.', intro:'A line of symmetry divides a shape into two mirror-image halves.', steps:[{title:'Fold test',body:'Fold the shape along a line. If both halves match exactly, it is a line of symmetry.'},{title:'Regular shapes',body:'Square: 4 lines. Rectangle: 2. Circle: infinite. Letter H: 2.'},{title:'Draw lines',body:'Draw dashed lines through all lines of symmetry.'},{title:'Non-symmetric',body:'Scalene triangle: 0 lines. Letter F: 0.'}], explanation:'Symmetry appears in art, architecture, biology, and chemistry — molecules, snowflakes, and faces.', exercises:[{question:'How many lines of symmetry does an equilateral triangle have?',answer:'3',hint:'One through each vertex to opposite midpoint.'},{question:'Does the letter Z have symmetry?',answer:'No reflective symmetry (but rotational)',hint:'Z looks different when flipped.'},{question:'How many lines of symmetry does a regular hexagon have?',answer:'6',hint:'3 through vertices, 3 through edge midpoints.'}]},
  { id:'time-elapsed', title:'Elapsed Time', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['elapsed time','duration','start end','hours minutes'], summary:'Calculate how much time has passed between two times.', intro:'Elapsed time is the duration between a start time and end time.', steps:[{title:'Count up method',body:'Start: 2:15 PM. End: 4:40 PM. Count hours: 2:15→4:15 = 2 hours. Then minutes: 4:15→4:40 = 25 min. Total: 2h 25min.'},{title:'Subtraction method',body:'Convert to minutes from midnight or line up digits carefully.'},{title:'Number line',body:'Draw time on a number line and hop forward.'},{title:'AM/PM',body:'Remember noon=12:00 PM, midnight=12:00 AM.'}], explanation:'Elapsed time is essential for scheduling, cooking, travel, and sports.', exercises:[{question:'Start 10:30 AM, end 1:15 PM. Duration?',answer:'2 hours 45 minutes',hint:'10:30→1:30=3h, minus 15 min=2h45m.'},{question:'Movie starts at 7:45 PM, runs 2h15m. Ends at?',answer:'10:00 PM',hint:'7:45+2:15=10:00.'},{question:'Race starts 9:00 AM, ends 9:45 AM. Duration?',answer:'45 minutes',hint:'Straight subtraction.'}]},
  { id:'prime-numbers', title:'Prime Numbers', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['prime','composite','factors','Sieve of Eratosthenes'], summary:'Identify prime numbers and distinguish them from composite numbers.', intro:'A prime number has exactly two factors: 1 and itself. All other numbers (>1) are composite.', steps:[{title:'Definition',body:'2, 3, 5, 7, 11, 13… are prime. 1 is neither prime nor composite.'},{title:'Test for primality',body:'Try dividing by 2, 3, 5, 7. If none divide evenly (up to √n), it is prime.'},{title:'Sieve of Eratosthenes',body:'Circle 2, cross all multiples. Circle 3, cross multiples. Continue. Circled = primes.'},{title:'Even primes',body:'2 is the only even prime. All other even numbers are divisible by 2.'}], explanation:'Primes are the building blocks of all integers. Modern encryption (RSA) relies on the difficulty of factoring large primes.', exercises:[{question:'Is 29 prime?',answer:'Yes',hint:'Not divisible by 2,3,5 — √29≈5.4.'},{question:'List all primes less than 20.',answer:'2,3,5,7,11,13,17,19',hint:'8 primes total.'},{question:'Is 1 prime?',answer:'No — 1 is neither prime nor composite.',hint:'Definition requires exactly 2 factors.'}]},
  { id:'adding-decimals', title:'Adding and Subtracting Decimals', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['decimals','add','subtract','align decimal point'], summary:'Add and subtract decimals by aligning the decimal point.', intro:'The rule for decimal arithmetic: always line up the decimal points before adding or subtracting.', steps:[{title:'Align decimal points',body:'Write numbers vertically with decimal points in the same column.'},{title:'Fill with zeros',body:'3.5 + 2.47 → 3.50 + 2.47. Zeros act as placeholders.'},{title:'Add/subtract normally',body:'Add or subtract each column right to left, carrying or borrowing as needed.'},{title:'Bring down decimal',body:'Place the decimal point in the answer directly below the aligned points.'}], explanation:'Decimal alignment is equivalent to finding a common denominator before adding fractions.', exercises:[{question:'3.6 + 1.28 = ?',answer:'4.88',hint:'3.60+1.28=4.88.'},{question:'7.5 - 2.34 = ?',answer:'5.16',hint:'7.50-2.34=5.16.'},{question:'0.9 + 0.15 + 1.2 = ?',answer:'2.25',hint:'0.90+0.15+1.20=2.25.'}]},
  { id:'congruent-shapes', title:'Congruent Shapes', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['congruent','same size','same shape','flip slide turn'], summary:'Identify congruent shapes that have equal size and shape.', intro:'Congruent shapes are identical in size and shape, even if flipped, rotated, or slid.', steps:[{title:'Definition',body:'Congruent = same shape AND same size. All angles and sides match.'},{title:'Transformations keep congruence',body:'Flip (reflect), slide (translate), turn (rotate) — all keep congruence.'},{title:'Resize breaks congruence',body:'Scaling changes size → similar, not congruent.'},{title:'Check with superimposition',body:'Imagine sliding one shape onto the other. If they line up perfectly, they are congruent.'}], explanation:'Congruence is the mathematical definition of "identical." Manufacturing uses it for interchangeable parts.', exercises:[{question:'Are two squares with side 5cm congruent?',answer:'Yes',hint:'Same size and shape.'},{question:'A triangle is reflected. Is the image congruent to the original?',answer:'Yes',hint:'Reflections preserve size and shape.'},{question:'Square 4cm and rectangle 4×4cm — congruent?',answer:'Yes',hint:'A square is a rectangle; both are 4×4.'}]},
  { id:'input-output-tables', title:'Input-Output Tables', grade:'35', gradeLabel:'3–5', subject:'algebra', tags:['input output','function','pattern','rule','table'], summary:'Find the rule connecting input and output values in a table.', intro:'An input-output table shows pairs of numbers connected by a consistent rule.', steps:[{title:'Look at a pair',body:'Input 3 → Output 9. Test: ×3 works.'},{title:'Verify with another pair',body:'Input 5 → Output 15. 5×3=15 ✓'},{title:'Write the rule',body:'Output = Input × 3, or y = 3x.'},{title:'Use the rule to predict',body:'Input 7 → Output 7×3=21.'}], explanation:'Input-output tables are the entry point to functions — one of the most important concepts in all of mathematics.', exercises:[{question:'Input→Output: 2→7, 4→9, 6→11. Rule?',answer:'Output = Input + 5',hint:'7-2=5.'},{question:'Rule: Output=Input×4. Input=8, Output=?',answer:'32',hint:'8×4=32.'},{question:'Rule: y=2x+1. x=6, y=?',answer:'13',hint:'2(6)+1=13.'}]},
  { id:'multiplying-decimals', title:'Multiplying Decimals', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['multiply decimals','decimal places','count'], summary:'Multiply decimals by counting total decimal places in the factors.', intro:'Multiply as if the numbers were whole numbers, then count decimal places.', steps:[{title:'Multiply without decimals',body:'2.3 × 1.4: ignore decimals → 23×14=322.'},{title:'Count decimal places',body:'2.3 has 1 place. 1.4 has 1 place. Total = 2 places.'},{title:'Insert decimal',body:'322 with 2 decimal places → 3.22.'},{title:'Estimate to check',body:'2×1=2 ≈ 3.22 ✓'}], explanation:'This works because 2.3×1.4 = 23/10 × 14/10 = 322/100 = 3.22.', exercises:[{question:'3.5 × 2.2 = ?',answer:'7.70',hint:'35×22=770. 2 places → 7.70.'},{question:'0.4 × 0.6 = ?',answer:'0.24',hint:'4×6=24. 2 places → 0.24.'},{question:'1.5 × 1.5 = ?',answer:'2.25',hint:'15×15=225. 2 places → 2.25.'}]},
  { id:'data-stem-leaf', title:'Stem-and-Leaf Plots', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['stem leaf','data display','median mode range'], summary:'Organize data using stem-and-leaf plots to find median and range.', intro:'A stem-and-leaf plot splits each number into a stem (tens) and leaf (ones) to show distribution.', steps:[{title:'Build the plot',body:'Data: 23,25,31,34,34,41. Stems: 2,3,4. Leaves: 2|35, 3|144, 4|1.'},{title:'Find median',body:'Order data. Middle value = median.'},{title:'Find mode',body:'Most common leaf under same stem.'},{title:'Find range',body:'Max - Min = 41-23=18.'}], explanation:'Stem-and-leaf plots show the shape of data while preserving individual values.', exercises:[{question:'Data: 45,47,52,52,58. Median?',answer:'52',hint:'Middle of 5 values.'},{question:'Same data. Mode?',answer:'52',hint:'Appears twice.'},{question:'Same data. Range?',answer:'13',hint:'58-45=13.'}]},
  { id:'line-graphs', title:'Line Graphs', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['line graph','change over time','trend','data'], summary:'Read and create line graphs to show change over time.', intro:'Line graphs display how a quantity changes over time. They highlight trends.', steps:[{title:'Read axes',body:'x-axis: time. y-axis: quantity.'},{title:'Identify trends',body:'Line going up = increasing. Line going down = decreasing. Flat = constant.'},{title:'Read specific values',body:'Find the time on x-axis, trace up to the line, trace left to y-axis.'},{title:'Calculate change',body:'Change = ending value - starting value.'}], explanation:'Line graphs are essential in science, economics, and medicine for tracking change over time.', exercises:[{question:'Temperature at 8am=60°, 12pm=75°. Change?',answer:'+15°',hint:'75-60=15.'},{question:'Line slopes down from left to right. Trend?',answer:'Decreasing',hint:'Down = decreasing.'},{question:'Why are line graphs better than bar graphs for temperature?',answer:'They show continuous change over time',hint:'Time series data needs a continuous line.'}]},
  { id:'angles-with-protractor', title:'Measuring Angles with a Protractor', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['protractor','measure angle','degrees'], summary:'Use a protractor to measure and draw angles in degrees.', intro:'A protractor is a semi-circular tool marked 0°–180° (or 0°–360°) for measuring angles.', steps:[{title:'Align the protractor',body:'Place the center mark on the vertex. Align the base line with one ray.'},{title:'Read the scale',body:'Follow the other ray to the scale. Use the correct scale (inner or outer).'},{title:'Estimate first',body:'Acute < 90°, obtuse > 90°. This helps you choose the right scale.'},{title:'Draw an angle',body:'Mark the vertex, draw one ray, then use the protractor to mark the desired degree, draw second ray.'}], explanation:'Protractors show that angles are rotation — the same way compass bearings work.', exercises:[{question:'Angle reads 65°. Acute or obtuse?',answer:'Acute',hint:'65 < 90.'},{question:'Draw a 135° angle. Classify it.',answer:'Obtuse',hint:'90 < 135 < 180.'},{question:'Two supplementary angles if one is 48°?',answer:'132°',hint:'180-48=132.'}]},
  { id:'fractions-on-number-line', title:'Fractions on a Number Line', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['fractions','number line','plot','equivalent fractions','compare'], summary:'Plot fractions on a number line and compare them.', intro:'A number line from 0 to 1 can show fractions as points representing parts of the whole.', steps:[{title:'Divide the line',body:'For thirds, divide 0–1 into 3 equal parts. Mark 1/3 and 2/3.'},{title:'Plot the fraction',body:'Count the correct number of sections from 0.'},{title:'Compare',body:'Numbers further right are larger. 2/3 > 1/3.'},{title:'Equivalent fractions',body:'1/2 = 2/4 = 4/8 — all land on the same point.'}], explanation:'The number line makes abstract fractions concrete and shows equivalence visually.', exercises:[{question:'Plot 3/4. Is it closer to 0 or 1?',answer:'Closer to 1',hint:'3/4 = 0.75.'},{question:'Which is further right: 1/3 or 2/5?',answer:'2/5',hint:'1/3≈0.33, 2/5=0.40.'},{question:'Name a fraction equivalent to 1/2 with denominator 8.',answer:'4/8',hint:'×4/×4.'}]},
  { id:'perimeter-and-area-complex', title:'Area of Composite Figures', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['area','composite','L-shape','subtract','add rectangles'], summary:'Find the area of L-shapes and composite figures by adding or subtracting rectangles.', intro:'Complex shapes can be split into rectangles or have rectangles removed.', steps:[{title:'Split into rectangles',body:'L-shape: draw a line to make two rectangles. Find each area and add.'},{title:'Or subtract',body:'Enclose in a large rectangle. Subtract the cut-out.'},{title:'Label all dimensions',body:'Find missing lengths using given dimensions.'},{title:'Add units²',body:'Area is always in square units.'}], explanation:'Composite area strategies develop spatial reasoning and prepare for calculus integration.', exercises:[{question:'L-shape: outer 8×6=48, cut 3×4=12. Area?',answer:'36 sq units',hint:'48-12=36.'},{question:'Two rectangles: 5×3 and 4×2. Total area?',answer:'23 sq units',hint:'15+8=23.'},{question:'T-shape: top 6×2, stem 2×4. Area?',answer:'20 sq units',hint:'12+8=20.'}]},
  { id:'multiplication-word-problems', title:'Multi-Step Word Problems', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['word problems','multi step','two step','operations'], summary:'Solve word problems requiring two or more operations.', intro:'Multi-step problems combine addition, subtraction, multiplication, or division in sequence.', steps:[{title:'Read carefully',body:'Identify all the given information and what is asked.'},{title:'Break into steps',body:'Solve the first step, use that result in the next step.'},{title:'Show work',body:'Write an equation for each step.'},{title:'Check reasonableness',body:'Does the answer make sense?'}], explanation:'Real-life problems rarely use just one operation. Breaking into steps is problem solving.', exercises:[{question:'48 students in 3 vans, then 6 more arrive. Total?',answer:'54',hint:'48+6=54.'},{question:'Pencils cost 25¢ each. Buy 7, give $2. Change?',answer:'25¢',hint:'7×25=175¢. 200-175=25¢.'},{question:'4 boxes of 12 pens. Gave 15 away. Left?',answer:'33',hint:'48-15=33.'}]},
  { id:'geometry-nets-3d', title:'Nets of 3D Shapes', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['net','3D shape','unfold','cube','rectangular prism'], summary:'Identify and draw nets — flat unfolds — of 3D shapes.', intro:'A net is a 2D figure that folds up into a 3D shape.', steps:[{title:'Cube net',body:'6 squares arranged in a cross or T-shape that fold into a cube.'},{title:'Rectangular prism net',body:'6 rectangles — top, bottom, front, back, left, right faces.'},{title:'Cylinder net',body:'2 circles + 1 rectangle (rolled into the curved side).'},{title:'Test a net',body:'Mentally fold it. Do all faces match? Are there gaps or overlaps?'}], explanation:'Nets are used in packaging design and cardboard box manufacturing.', exercises:[{question:'A cube net has how many squares?',answer:'6',hint:'Cube has 6 faces.'},{question:'A cylinder net has how many shapes?',answer:'3 (2 circles + 1 rectangle)',hint:'2 bases + curved surface.'},{question:'True/False: Any arrangement of 6 squares is a cube net.',answer:'False',hint:'They must fold up without overlap.'}]},
  { id:'division-by-two-digits', title:'Dividing by Two-Digit Divisors', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['division','two-digit divisor','estimate quotient'], summary:'Divide a 3- or 4-digit number by a 2-digit divisor using estimation.', intro:'When dividing by a 2-digit number, estimate the divisor as a round number.', steps:[{title:'Round the divisor',body:'756÷21: round 21 to 20.'},{title:'Estimate quotient digit',body:'How many 20s in 75? About 3. Write 3 above 6th digit position.'},{title:'Multiply and subtract',body:'3×21=63. 75-63=12. Bring down 6: 126.'},{title:'Repeat',body:'126÷21=6. 6×21=126. Remainder 0. Answer: 36.'}], explanation:'Estimation makes 2-digit division manageable. Adjust if your estimate is too high or too low.', exercises:[{question:'828÷36=?',answer:'23',hint:'36×20=720, 828-720=108, 108/36=3. Total 23.'},{question:'546÷13=?',answer:'42',hint:'13×40=520, 546-520=26, 26/13=2.'},{question:'672÷24=?',answer:'28',hint:'24×28=672.'}]},
  { id:'estimating-products', title:'Estimating Products and Quotients', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['estimation','products','quotients','round'], summary:'Estimate the results of multiplication and division using rounding.', intro:'Estimation gives a quick approximate answer to check if exact calculations are reasonable.', steps:[{title:'Round factors',body:'38×22 ≈ 40×20=800.'},{title:'Round for division',body:'157÷8 ≈ 160÷8=20.'},{title:'Compatible numbers',body:'Choose numbers that are easy to compute: 247÷5 ≈ 250÷5=50.'},{title:'Check exact',body:'38×22=836. Estimate 800 is close ✓'}], explanation:'Compatible numbers are the quickest form of mental estimation.', exercises:[{question:'Estimate 52×19.',answer:'≈1000',hint:'50×20=1000.'},{question:'Estimate 243÷6.',answer:'≈40',hint:'240÷6=40.'},{question:'Estimate 76×49.',answer:'≈4000',hint:'80×50=4000.'}]},
  { id:'us-standard-measurement', title:'US Customary Measurements', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['measurement','inches','feet','yards','ounces','pounds','cups','pints'], summary:'Convert between US customary units of length, weight, and capacity.', intro:'The US system uses feet, pounds, and cups. Conversions must be memorized.', steps:[{title:'Length',body:'12 in = 1 ft. 3 ft = 1 yd. 1760 yd = 1 mile.'},{title:'Weight',body:'16 oz = 1 lb. 2000 lb = 1 ton.'},{title:'Capacity',body:'8 fl oz = 1 cup. 2 cups = 1 pint. 2 pints = 1 quart. 4 quarts = 1 gallon.'},{title:'Convert',body:'To go to smaller units: multiply. To go to larger: divide.'}], explanation:'US customary units are historical — Britain converted to metric, the US largely has not.', exercises:[{question:'3 feet = how many inches?',answer:'36 inches',hint:'3×12=36.'},{question:'32 ounces = how many pounds?',answer:'2 pounds',hint:'32÷16=2.'},{question:'3 quarts = how many cups?',answer:'12 cups',hint:'3×2×2=12.'}]},
  { id:'metric-measurement', title:'Metric Measurement', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['metric','centimeter','meter','kilometer','gram','kilogram','liter'], summary:'Use and convert metric units of length, mass, and volume.', intro:'The metric system uses prefixes based on powers of 10. Kilo=1000, centi=1/100, milli=1/1000.', steps:[{title:'Length prefixes',body:'km > m > dm > cm > mm. 1 m = 100 cm = 1000 mm.'},{title:'Mass',body:'1 kg = 1000 g. 1 g = 1000 mg.'},{title:'Volume',body:'1 L = 1000 mL.'},{title:'Convert',body:'km→m: multiply by 1000. m→cm: multiply by 100.'}], explanation:'The metric system was designed for science — each unit relates to the next by a power of 10.', exercises:[{question:'4.5 km = ? m',answer:'4500 m',hint:'×1000.'},{question:'250 cm = ? m',answer:'2.5 m',hint:'÷100.'},{question:'3500 mL = ? L',answer:'3.5 L',hint:'÷1000.'}]},

  // ── Grades 6–8 ─────────────────────────────────────────────────────────────
  { id:'slope-formula', title:'Slope Formula', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['slope','rise over run','two points','gradient','m'], summary:'Calculate slope between two points using the slope formula m=(y₂-y₁)/(x₂-x₁).', intro:'Slope measures the steepness of a line. Between any two points, it is constant.', steps:[{title:'Formula',body:'m = (y₂-y₁)/(x₂-x₁). Rise over run.'},{title:'Identify points',body:'(1,3) and (4,9): x₁=1,y₁=3,x₂=4,y₂=9.'},{title:'Substitute',body:'m=(9-3)/(4-1)=6/3=2.'},{title:'Interpret',body:'m=2: rise 2 for every 1 run. Positive = uphill left to right.'}], explanation:'Negative slope = downhill. Zero slope = horizontal. Undefined slope = vertical.', exercises:[{question:'Slope between (2,5) and (6,13)?',answer:'2',hint:'(13-5)/(6-2)=8/4=2.'},{question:'Slope between (0,0) and (3,-6)?',answer:'-2',hint:'(-6-0)/(3-0)=-2.'},{question:'Slope of a horizontal line?',answer:'0',hint:'No rise: 0/run=0.'}]},
  { id:'graphing-linear-inequalities', title:'Graphing Linear Inequalities', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['linear inequalities','graph','shade','dashed solid line'], summary:'Graph linear inequalities by drawing the boundary line and shading.', intro:'A linear inequality has a region of solutions, not just a line.', steps:[{title:'Replace inequality with =',body:'y>2x+1 → y=2x+1. Graph this line.'},{title:'Solid or dashed',body:'≤ or ≥ → solid line (edge included). < or > → dashed (edge not included).'},{title:'Shade',body:'y>2x+1: shade ABOVE the line. y<2x+1: shade BELOW.'},{title:'Test a point',body:'Test (0,0) in y>2x+1: 0>1? No → shade the other side.'}], explanation:'The shaded region contains all (x,y) pairs that satisfy the inequality.', exercises:[{question:'Graph y<x+3. Solid or dashed?',answer:'Dashed',hint:'Strict < uses dashed.'},{question:'Test (2,2) in y≥2x-1.',answer:'2≥3? No — (2,2) is not in the solution.',hint:'2≥4-1=3? 2<3.'},{question:'y>0: shade above or below x-axis?',answer:'Above',hint:'y>0 means above the x-axis.'}]},
  { id:'writing-expressions', title:'Writing Algebraic Expressions', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['algebraic expression','variable','translate','write expression'], summary:'Translate word phrases into algebraic expressions.', intro:'Algebra uses symbols to represent unknown quantities. Translating words to symbols is the first skill.', steps:[{title:'Key word translations',body:'"sum" → +. "difference" → -. "product" → ×. "quotient" → ÷. "more than" → +. "less than" → -.  "of" → ×.'},{title:'Example',body:'"5 more than twice a number" → 2n+5.'},{title:'Variable choice',body:'Use n, x, or any letter for the unknown.'},{title:'Careful with order',body:'"7 less than x" = x-7, NOT 7-x.'}], explanation:'Translating precisely is the first step toward setting up equations and solving real problems.', exercises:[{question:'8 less than 3 times a number.',answer:'3n-8',hint:'"Less than" means subtract after.'},{question:'The quotient of n and 4, increased by 6.',answer:'n/4+6',hint:'Quotient = divide.'},{question:'Twice the sum of x and 9.',answer:'2(x+9)',hint:'Sum first, then double.'}]},
  { id:'two-step-equations', title:'Two-Step Equations', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['two step equations','solve','algebra','inverse operations'], summary:'Solve equations requiring two inverse operations.', intro:'Two-step equations have two operations applied to the variable.', steps:[{title:'Undo in reverse order',body:'2x+5=11. The +5 was done last, so undo it first: 2x=6.'},{title:'Then undo multiplication',body:'2x=6 → divide by 2 → x=3.'},{title:'Check',body:'2(3)+5=11 ✓'},{title:'Variables on both sides',body:'3x+2=x+8 → 2x=6 → x=3.'}], explanation:'Always undo addition/subtraction before multiplication/division — reverse PEMDAS.', exercises:[{question:'5x-3=17',answer:'x=4',hint:'Add 3: 5x=20. Divide by 5.'},{question:'x/3+7=10',answer:'x=9',hint:'Subtract 7: x/3=3. Multiply by 3.'},{question:'4(x-2)=20',answer:'x=7',hint:'Divide by 4: x-2=5. Add 2.'}]},
  { id:'angle-sum-triangles', title:'Angle Sum in Triangles', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['triangle angles','180 degrees','sum','interior angles'], summary:'Use the Triangle Angle Sum Theorem to find missing angles.', intro:'The three interior angles of any triangle always add up to exactly 180°.', steps:[{title:'Triangle Angle Sum Theorem',body:'A+B+C=180° for any triangle.'},{title:'Find missing angle',body:'Two angles: 55° and 75°. Third: 180-55-75=50°.'},{title:'Right triangle',body:'One angle is 90°. Other two sum to 90° (complementary).'},{title:'Isosceles triangle',body:'Two equal base angles. 180-vertex angle = sum of base angles. Each = half.'}], explanation:'This theorem follows from parallel lines cut by a transversal.', exercises:[{question:'Angles 43° and 97°. Find third.',answer:'40°',hint:'180-43-97=40.'},{question:'Right triangle with one angle 35°. Find the other.',answer:'55°',hint:'90-35=55.'},{question:'Isosceles: vertex angle 40°. Base angles?',answer:'70° each',hint:'(180-40)/2=70.'}]},
  { id:'exterior-angles', title:'Exterior Angles of Triangles', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['exterior angle','remote interior','triangle'], summary:'Apply the Exterior Angle Theorem to find unknown angles.', intro:'An exterior angle of a triangle equals the sum of the two non-adjacent (remote) interior angles.', steps:[{title:'Exterior angle',body:'Extend one side of a triangle. The exterior angle is formed outside the triangle.'},{title:'Theorem',body:'Exterior angle = sum of two remote interior angles.'},{title:'Apply',body:'Remote angles 40° and 65°. Exterior angle = 105°.'},{title:'Linear pair check',body:'Exterior + adjacent interior = 180° (linear pair).'}], explanation:'The Exterior Angle Theorem is a direct consequence of the Triangle Angle Sum Theorem.', exercises:[{question:'Remote angles 50° and 70°. Exterior angle?',answer:'120°',hint:'50+70=120.'},{question:'Exterior angle 110°, one remote interior 45°. Other?',answer:'65°',hint:'110-45=65.'},{question:'Exterior angle 135°. Adjacent interior?',answer:'45°',hint:'180-135=45.'}]},
  { id:'rates-unit-rates', title:'Unit Rates in Context', grade:'68', gradeLabel:'6–8', subject:'fractions', tags:['unit rate','rate','per','miles per hour','price per item'], summary:'Calculate and interpret unit rates in real-world contexts.', intro:'A unit rate is a ratio with a denominator of 1. It tells "per one."', steps:[{title:'Divide to get 1',body:'240 miles in 4 hours: 240÷4=60 miles per hour.'},{title:'Price per unit',body:'$3.60 for 12 eggs: $3.60÷12=$0.30 per egg.'},{title:'Compare rates',body:'Store A: $2.40/6 = $0.40 each. Store B: $3.50/8 = $0.4375 each. Store A is cheaper.'},{title:'Unit rate in equations',body:'y = 12x: $12 per hour. Unit rate = 12.'}], explanation:'Unit rates let us make fair comparisons between different-sized quantities.', exercises:[{question:'360 km in 3 hours. Speed?',answer:'120 km/h',hint:'360÷3=120.'},{question:'5 lbs for $8.25. Price per lb?',answer:'$1.65',hint:'8.25÷5=1.65.'},{question:'Store A: 3 for $1.20. Store B: 5 for $2.15. Better deal?',answer:'Store A ($0.40 vs $0.43)',hint:'Compare unit prices.'}]},
  { id:'solving-equations-variables-both-sides', title:'Equations with Variables on Both Sides', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['equations','variables both sides','algebra','solve'], summary:'Solve equations where the variable appears on both sides.', intro:'Collect variable terms on one side, constants on the other.', steps:[{title:'Move variable terms',body:'5x-4=3x+6. Subtract 3x: 2x-4=6.'},{title:'Move constants',body:'Add 4: 2x=10.'},{title:'Divide',body:'x=5.'},{title:'Check',body:'5(5)-4=21. 3(5)+6=21. ✓'}], explanation:'The key principle: equals stay equal as long as you do the same thing to both sides.', exercises:[{question:'7x+3=4x+12',answer:'x=3',hint:'3x=9.'},{question:'2(x+4)=x+11',answer:'x=3',hint:'2x+8=x+11.'},{question:'6x-5=2x+7',answer:'x=3',hint:'4x=12.'}]},
  { id:'area-triangle-trapezoid', title:'Area of Triangles and Trapezoids', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['area','triangle','trapezoid','formula'], summary:'Apply area formulas for triangles and trapezoids.', intro:'Each polygon has a specific area formula derived from the rectangle formula.', steps:[{title:'Triangle',body:'A = ½ × base × height. Height must be perpendicular to the base.'},{title:'Trapezoid',body:'A = ½(b₁+b₂)×h. Average the two parallel bases, then multiply by height.'},{title:'Height vs slant',body:'Height is always perpendicular — never the slanted side.'},{title:'Check units',body:'cm² or m².'}], explanation:'Triangle area = half of parallelogram (base × height). Trapezoid = average base × height.', exercises:[{question:'Triangle: base=10, height=6. Area?',answer:'30 sq units',hint:'½×10×6=30.'},{question:'Trapezoid: bases 5 and 9, height 4. Area?',answer:'28 sq units',hint:'½(5+9)×4=28.'},{question:'Triangle area=24, base=8. Height?',answer:'6',hint:'24=½×8×h → h=6.'}]},
  { id:'histograms', title:'Histograms', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['histogram','frequency','intervals','bar graph','distribution'], summary:'Create and interpret histograms showing frequency distributions.', intro:'A histogram groups continuous data into intervals and shows frequency as bar heights.', steps:[{title:'Choose intervals',body:'Equal width intervals covering all data. 0-10, 10-20, 20-30…'},{title:'Count frequencies',body:'Tally how many values fall in each interval.'},{title:'Draw bars',body:'Bars touch (continuous data). Height = frequency.'},{title:'Interpret',body:'Tallest bar = most common interval. Shape reveals distribution.'}], explanation:'Histograms reveal whether data is symmetric, skewed left, or skewed right.', exercises:[{question:'Most bars are on the left, tail on right. Shape?',answer:'Skewed right (positive skew)',hint:'Tail points right.'},{question:'Two equal peaks. Shape?',answer:'Bimodal',hint:'Two modes.'},{question:'Why do histogram bars touch?',answer:'Data is continuous — no gaps between values.',hint:'Unlike categorical bar graphs.'}]},
  { id:'volume-cylinder-cone', title:'Volume of Cylinders and Cones', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['volume','cylinder','cone','pi','radius','height'], summary:'Calculate volumes of cylinders and cones using π.', intro:'Cylinders and cones use π because their cross-section is a circle.', steps:[{title:'Cylinder formula',body:'V = πr²h. r=radius of base, h=height.'},{title:'Cone formula',body:'V = ⅓πr²h. Exactly ⅓ of a cylinder with same r and h.'},{title:'Plug in',body:'Cylinder r=3, h=5: V=π(9)(5)=45π≈141.4.'},{title:'Units',body:'Always cubic units (cm³).'}], explanation:'A cone has 1/3 the volume of its cylinder. Fill a cone 3 times to fill the cylinder — verify with sand!', exercises:[{question:'Cylinder r=2, h=10. Volume?',answer:'40π≈125.7 cm³',hint:'π(4)(10)=40π.'},{question:'Cone r=3, h=9. Volume?',answer:'27π≈84.8 cm³',hint:'⅓π(9)(9)=27π.'},{question:'Cylinder and cone same r and h. Volume ratio?',answer:'3:1',hint:'Cylinder is 3× the cone.'}]},
  { id:'solving-inequalities-graphs', title:'Graphing Inequalities on a Number Line', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['inequality','number line','graph','open closed circle'], summary:'Graph inequalities on a number line using open and closed circles.', intro:'A number line graph shows all solutions to an inequality.', steps:[{title:'Open circle ○',body:'For < or >: open circle at the boundary (boundary NOT included).'},{title:'Closed circle ●',body:'For ≤ or ≥: filled circle (boundary included).'},{title:'Arrow direction',body:'x>3: arrow pointing right from 3.'},{title:'Compound',body:'2<x≤7: open circle at 2, closed at 7, segment between.'}], explanation:'Number line graphs visually represent infinite solution sets.', exercises:[{question:'Graph x ≤ -2.',answer:'Closed circle at -2, arrow left.',hint:'≤ is closed.'},{question:'Graph -1 < x < 4.',answer:'Open circles at -1 and 4, segment between.',hint:'Both strict inequalities.'},{question:'Is x=5 a solution to x>5?',answer:'No',hint:'Strict > excludes the boundary.'}]},
  { id:'pi-circles', title:'Circumference and Area of Circles', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['circle','pi','circumference','area','radius','diameter'], summary:'Calculate circumference and area of circles using π.', intro:'π (pi) ≈ 3.14159 is the ratio of circumference to diameter for every circle.', steps:[{title:'Circumference',body:'C = πd = 2πr. Diameter d = 2r.'},{title:'Area',body:'A = πr².'},{title:'Plug in',body:'r=7: C=14π≈43.98. A=49π≈153.94.'},{title:'Use π button',body:'Use calculator π or approximate as 3.14159.'}], explanation:'π is irrational and transcendental — its decimal never repeats or terminates.', exercises:[{question:'Circle d=10. Circumference?',answer:'10π≈31.42',hint:'C=πd=10π.'},{question:'Circle r=6. Area?',answer:'36π≈113.1',hint:'A=π×36.'},{question:'Circumference=8π. Radius?',answer:'r=4',hint:'8π=2πr → r=4.'}]},
  { id:'exponents-basics', title:'Exponents (Basics)', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['exponents','powers','base','squared','cubed'], summary:'Evaluate exponential expressions using base and exponent.', intro:'An exponent tells you how many times to multiply the base by itself.', steps:[{title:'Parts',body:'2³: base=2, exponent=3. Means 2×2×2=8.'},{title:'Special cases',body:'x¹=x. x⁰=1. x²="x squared." x³="x cubed."'},{title:'Powers of 10',body:'10³=1000. 10⁴=10000. Exponent = number of zeros.'},{title:'Order of operations',body:'Exponents before ×, ÷, +, -.'}], explanation:'Exponentiation is repeated multiplication, just as multiplication is repeated addition.', exercises:[{question:'3⁴=?',answer:'81',hint:'3×3×3×3=81.'},{question:'5²+2³=?',answer:'33',hint:'25+8=33.'},{question:'10⁵=?',answer:'100,000',hint:'5 zeros.'}]},
  { id:'cube-roots', title:'Square Roots and Cube Roots', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['square root','cube root','radical','perfect square','irrational'], summary:'Evaluate square roots and cube roots of perfect squares and cubes.', intro:'A square root reverses squaring. A cube root reverses cubing.', steps:[{title:'Square roots',body:'√49=7 because 7²=49. Perfect squares: 1,4,9,16,25,36,49,64,81,100…'},{title:'Cube roots',body:'∛27=3 because 3³=27.'},{title:'Non-perfect squares',body:'√20 is between 4 (√16) and 5 (√25). ≈4.47.'},{title:'Simplify radicals',body:'√50=√25×2=5√2.'}], explanation:'√2 is irrational — proved by the ancient Greeks. It cannot be written as a fraction.', exercises:[{question:'√81=?',answer:'9',hint:'9²=81.'},{question:'∛64=?',answer:'4',hint:'4³=64.'},{question:'Between which two integers is √50?',answer:'7 and 8',hint:'7²=49, 8²=64.'}]},
  { id:'pythagorean-theorem-applied', title:'Pythagorean Theorem in Context', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['Pythagorean','context','distance','diagonal','real world'], summary:'Apply the Pythagorean Theorem to real-world problems.', intro:'The theorem helps find distances wherever a right angle exists.', steps:[{title:'Identify the right angle',body:'The right angle is where the two legs meet.'},{title:'Label correctly',body:'Hypotenuse = longest side opposite the right angle.'},{title:'Set up equation',body:'a²+b²=c²'},{title:'Real contexts',body:'TV screen diagonal, ladder against wall, distance between two points on a grid.'}], explanation:'Distance formula is Pythagorean theorem applied to coordinate geometry.', exercises:[{question:'Screen 24"×32". Diagonal?',answer:'40"',hint:'24²+32²=576+1024=1600=40².'},{question:'Ladder 15ft, 9ft from wall. Reach height?',answer:'12 ft',hint:'15²-9²=225-81=144=12².'},{question:'Points (1,1) and (4,5). Distance?',answer:'5',hint:'√(9+16)=5.'}]},
  { id:'integer-number-line', title:'Integers on the Number Line', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['integers','number line','negative','positive','order'], summary:'Order integers and find absolute value on the number line.', intro:'Integers include all whole numbers and their negatives: …-3,-2,-1,0,1,2,3…', steps:[{title:'Position on number line',body:'Negative numbers go left of 0. Positive go right.'},{title:'Ordering',body:'-5 < -2 < 0 < 3. Further left = smaller.'},{title:'Absolute value',body:'|x| = distance from 0. |-7|=7, |4|=4.'},{title:'Opposite numbers',body:'-3 and 3 are opposites: same distance from 0, opposite sides.'}], explanation:'The number line extends infinitely in both directions, representing all integers.', exercises:[{question:'Order: -3, 5, -7, 0, 2.',answer:'-7,-3,0,2,5',hint:'Most negative first.'},{question:'|-8|+|3|=?',answer:'11',hint:'8+3=11.'},{question:'Opposite of -12?',answer:'12',hint:'Same distance, other side of 0.'}]},
  { id:'percent-proportions', title:'Percent Proportions', grade:'68', gradeLabel:'6–8', subject:'fractions', tags:['percent','proportion','is over of','cross multiply'], summary:'Solve percent problems using the is/of proportion method.', intro:'Every percent problem fits: part/whole = percent/100.', steps:[{title:'Identify parts',body:'"What is 30% of 80?" Part=?, Whole=80, Percent=30.'},{title:'Set up proportion',body:'?/80 = 30/100.'},{title:'Cross multiply',body:'100×? = 30×80 = 2400. ? = 24.'},{title:'All three problem types',body:'Find part: ?/W = P/100. Find whole: p/? = P/100. Find percent: p/W = ?/100.'}], explanation:'Percent proportion is universal — works for any of the three unknowns.', exercises:[{question:'What is 45% of 120?',answer:'54',hint:'?/120=45/100. ?=54.'},{question:'18 is what percent of 72?',answer:'25%',hint:'18/72=?/100. ?=25.'},{question:'16 is 40% of what?',answer:'40',hint:'16/?=40/100. ?=40.'}]},
  { id:'representing-proportional-relationships', title:'Proportional Relationships', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['proportional','constant of proportionality','k','direct variation','graph'], summary:'Identify proportional relationships and find the constant of proportionality.', intro:'Two quantities are proportional when y=kx for a constant k.', steps:[{title:'Check ratio',body:'If y/x is always the same constant k, the relationship is proportional.'},{title:'Find k',body:'(2,6): k=6/2=3. (4,12): k=12/4=3. Proportional with k=3.'},{title:'Graph',body:'Proportional graphs pass through (0,0) and are straight lines.'},{title:'Write equation',body:'y=3x.'}], explanation:'Proportional relationships are the simplest linear functions — they pass through the origin.', exercises:[{question:'Table: (1,4),(2,8),(3,12). Is it proportional?',answer:'Yes, k=4',hint:'8/2=4, 12/3=4.'},{question:'y=5x. When x=7, y=?',answer:'35',hint:'5×7=35.'},{question:'Does a proportional graph pass through (0,0)?',answer:'Yes',hint:'When x=0, y=kx=0.'}]},
  { id:'multi-step-percent-problems', title:'Multi-Step Percent Problems', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['percent increase','percent decrease','markup','discount','compound change'], summary:'Solve multi-step problems involving percent increase and decrease.', intro:'Many real-world situations involve successive percent changes.', steps:[{title:'Percent increase',body:'New=Original×(1+r). 200+15%: 200×1.15=230.'},{title:'Percent decrease',body:'New=Original×(1-r). 200-15%: 200×0.85=170.'},{title:'Sequential changes',body:'Price $100, up 20% then down 20%: 100×1.2×0.8=$96 (not $100!).'}], explanation:'Successive percent changes are not simply additive — they multiply.', exercises:[{question:'$250 raised by 12%. New price?',answer:'$280',hint:'250×1.12=280.'},{question:'$80 reduced by 25%. New price?',answer:'$60',hint:'80×0.75=60.'},{question:'$100 up 10% then down 10%. Final?',answer:'$99',hint:'100×1.1×0.9=99.'}]},
  { id:'geometry-triangles-classification', title:'Classifying Triangles', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['triangle','equilateral','isosceles','scalene','acute','obtuse'], summary:'Classify triangles by their sides and angles.', intro:'Triangles are classified two ways: by side lengths and by angle types.', steps:[{title:'By sides',body:'Equilateral: all 3 sides equal. Isosceles: 2 equal. Scalene: none equal.'},{title:'By angles',body:'Acute: all angles <90°. Right: one angle =90°. Obtuse: one angle >90°.'},{title:'Combine',body:'"Right isosceles": right angle + 2 equal sides. "Acute scalene": all acute + no equal sides.'},{title:'Equilateral is also equiangular',body:'All sides equal → all angles 60°.'}], explanation:'These classifications set up congruence and similarity theorems.', exercises:[{question:'Triangle with sides 5,5,8. Type?',answer:'Isosceles',hint:'Two equal sides.'},{question:'Triangle angles 30°,60°,90°. Type by angle?',answer:'Right',hint:'One 90° angle.'},{question:'All sides different, all angles <90°. Type?',answer:'Acute scalene',hint:'No equal sides + all acute.'}]},
  { id:'scale-drawings', title:'Scale Drawings and Maps', grade:'68', gradeLabel:'6–8', subject:'fractions', tags:['scale','map','blueprint','scale factor','ratio'], summary:'Use scale factors to find actual distances from scale drawings.', intro:'A scale drawing represents a real object using a constant ratio.', steps:[{title:'Read the scale',body:'Scale 1:50 means 1 cm on drawing = 50 cm real.'},{title:'Set up proportion',body:'1/50 = measured/actual. Solve for actual.'},{title:'Map scales',body:'1 in = 20 miles. If distance on map = 3.5 in, actual = 70 miles.'},{title:'Find drawing length',body:'Actual=200m, scale=1:100. Drawing=2m.'}], explanation:'Engineers, architects, and cartographers use scale drawings daily.', exercises:[{question:'Scale 1cm:5m. Drawing=8cm. Actual length?',answer:'40m',hint:'8×5=40.'},{question:'Scale 1in:30mi. Map distance=4.5in. Actual?',answer:'135 miles',hint:'4.5×30=135.'},{question:'Room 12m long, scale 1:200. Drawing length?',answer:'6cm',hint:'12/200=0.06m=6cm.'}]},
  { id:'circumference-applications', title:'Arc Length and Sector Area', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['arc length','sector','central angle','pie slice'], summary:'Calculate arc length and sector area using central angle ratios.', intro:'A sector is a pie-slice of a circle. Its size is proportional to its central angle.', steps:[{title:'Arc length',body:'L = (θ/360)×2πr. θ = central angle.'},{title:'Sector area',body:'A = (θ/360)×πr².'},{title:'Example',body:'r=6, θ=90°. Arc=(90/360)×12π=3π. Area=(90/360)×36π=9π.'},{title:'Full circle check',body:'θ=360: arc=2πr ✓. Area=πr² ✓.'}], explanation:'Arc length and sector area are fractions of the full circle, proportional to central angle.', exercises:[{question:'r=10, θ=60°. Arc length?',answer:'10π/3≈10.47',hint:'(60/360)×20π=10π/3.'},{question:'r=8, θ=90°. Sector area?',answer:'16π≈50.3',hint:'(90/360)×64π=16π.'},{question:'Arc length=4π, r=6. Central angle?',answer:'120°',hint:'(θ/360)×12π=4π → θ=120.'}]},
  { id:'sampling-statistics', title:'Sampling in Statistics', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['sample','population','representative','random','inference'], summary:'Understand how to draw valid statistical conclusions from samples.', intro:'A sample is a subset of a population. A good sample represents the whole fairly.', steps:[{title:'Define population',body:'Everyone or everything you want to study.'},{title:'Random sample',body:'Every member has an equal chance of being selected.'},{title:'Convenience sample (bad)',body:'Select whoever is easiest. Biased and unreliable.'},{title:'Make inferences',body:'From sample statistics, estimate population parameters.'}], explanation:'Polls, clinical trials, and quality control all rely on careful sampling.', exercises:[{question:'Survey only students in your class about school lunch. Bias?',answer:'Convenience bias — not representative',hint:'Only one class.'},{question:'500 randomly selected adults: 60% prefer A. Inference?',answer:'About 60% of all adults prefer A',hint:'Random sample → valid inference.'},{question:'Why not survey everyone (census)?',answer:'Too costly, time-consuming, or impossible',hint:'That is why samples exist.'}]},
  { id:'geometric-mean', title:'Geometric Mean', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['geometric mean','root','growth','ratio'], summary:'Calculate and apply the geometric mean for proportional data.', intro:'The geometric mean is the nth root of the product of n values. Best for multiplicative data.', steps:[{title:'Formula',body:'GM = ⁿ√(x₁×x₂×…×xₙ).'},{title:'Two values',body:'GM of 4 and 9: √(36)=6.'},{title:'When to use',body:'Use for growth rates, ratios, interest rates — not simple averages.'},{title:'Compare to arithmetic mean',body:'AM(4,9)=6.5. GM=6. For non-negative data, GM≤AM.'}], explanation:'Geometric mean is used in finance (compound returns) and biology (population growth).', exercises:[{question:'Geometric mean of 2 and 8?',answer:'4',hint:'√(16)=4.'},{question:'GM of 1,3,9?',answer:'3',hint:'∛27=3.'},{question:'Investment grows 10%, then 40%. Effective rate?',answer:'≈24.0% (GM of 1.1 and 1.4)',hint:'√(1.1×1.4)-1≈0.24.'}]},
  { id:'compound-events-probability', title:'Compound Events & Counting', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['compound event','multiplication principle','tree diagram','independent events'], summary:'Count outcomes of compound events using tree diagrams and multiplication.', intro:'Compound events involve multiple stages. The multiplication principle counts outcomes.', steps:[{title:'Multiplication principle',body:'Flip a coin AND roll a die: 2×6=12 outcomes.'},{title:'Tree diagram',body:'Draw branches for each stage. Count terminal branches.'},{title:'Independent events',body:'P(A and B)=P(A)×P(B) if independent.'},{title:'Dependent events',body:'Without replacement: P(A then B)=P(A)×P(B|A).'}], explanation:'The multiplication principle is the foundation of combinatorics and probability.', exercises:[{question:'3 shirts, 4 pants. Outfits?',answer:'12',hint:'3×4=12.'},{question:'P(two heads) with fair coin twice?',answer:'1/4',hint:'1/2×1/2.'},{question:'Bag 5 red, 3 blue. Draw two without replacement. P(both red)?',answer:'5/8×4/7=20/56=5/14',hint:'5/8 then 4/7.'}]},

  // ── Grades 9–12 ────────────────────────────────────────────────────────────
  { id:'polynomial-long-division', title:'Polynomial Long Division', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['polynomial division','long division','divide polynomials','remainder'], summary:'Divide polynomials using long division.', intro:'Polynomial division parallels integer long division.', steps:[{title:'Set up',body:'(x³+2x²-5x+6)÷(x-1).'},{title:'Divide leading terms',body:'x³÷x=x². Write x².'},{title:'Multiply and subtract',body:'x²(x-1)=x³-x². Subtract: 3x²-5x+6.'},{title:'Repeat',body:'3x²÷x=3x. 3x(x-1)=3x²-3x. Subtract: -2x+6. Then -2x÷x=-2. -2(x-1)=-2x+2. Remainder 4.'},{title:'Answer',body:'x²+3x-2 + 4/(x-1).'}], explanation:'Polynomial division is used to find factors and analyze rational functions.', exercises:[{question:'(x²+5x+6)÷(x+2)=?',answer:'x+3',hint:'(x+3)(x+2)=x²+5x+6.'},{question:'(x²-1)÷(x-1)=?',answer:'x+1',hint:'Difference of squares.'},{question:'(2x²+x-3)÷(x-1)=?',answer:'2x+3',hint:'Check: (2x+3)(x-1)=2x²+x-3.'}]},
  { id:'synthetic-division', title:'Synthetic Division', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['synthetic division','polynomial','shortcut','remainder theorem'], summary:'Use synthetic division as a shortcut for dividing by linear factors.', intro:'Synthetic division is a faster notation for polynomial long division when dividing by (x-c).', steps:[{title:'Write coefficients',body:'(x³-3x²+x-2)÷(x-2): use coefficients [1,-3,1,-2] and c=2.'},{title:'Bring down first',body:'Bring down 1.'},{title:'Multiply and add',body:'1×2=2. -3+2=-1. -1×2=-2. 1+(-2)=-1. -1×2=-2. -2+(-2)=-4.'},{title:'Interpret',body:'Results: [1,-1,-1] with remainder -4. Quotient: x²-x-1 R-4.'}], explanation:'The Remainder Theorem: when f(x) is divided by (x-c), the remainder equals f(c).', exercises:[{question:'(x³-5x²+7x-3)÷(x-1). Remainder?',answer:'0 (x=1 is a root)',hint:'f(1)=1-5+7-3=0.'},{question:'Use synthetic division: (x³+2x²-x-2)÷(x+1)',answer:'x²+x-2',hint:'c=-1. Coefficients: 1,2,-1,-2.'}]},
  { id:'rational-exponents', title:'Rational Exponents', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['rational exponents','fractional exponents','radicals','convert'], summary:'Convert between radical and exponential form and evaluate.', intro:'A rational exponent a^(m/n) = ⁿ√(aᵐ).', steps:[{title:'Basic form',body:'a^(1/n) = ⁿ√a. 8^(1/3)=∛8=2.'},{title:'General form',body:'a^(m/n) = (ⁿ√a)ᵐ or ⁿ√(aᵐ).'},{title:'Simplify',body:'27^(2/3)=(∛27)²=3²=9.'},{title:'Negative rational exponents',body:'a^(-m/n)=1/a^(m/n).'}], explanation:'Rational exponents unify the language of powers and roots.', exercises:[{question:'16^(3/4)=?',answer:'8',hint:'(⁴√16)³=2³=8.'},{question:'x^(1/2)×x^(3/2)=?',answer:'x²',hint:'Add exponents: 1/2+3/2=2.'},{question:'Convert: ∛(x⁵)',answer:'x^(5/3)',hint:'Root=denominator, power=numerator.'}]},
  { id:'logarithm-equations', title:'Solving Logarithmic Equations', grade:'912', gradeLabel:'9–12', subject:'precalculus', tags:['logarithm','equation','log','exponent','solve'], summary:'Solve equations containing logarithms by converting or using log rules.', intro:'Use the definition logₐ(x)=y ↔ aʸ=x and log rules to solve.', steps:[{title:'Convert to exponential',body:'log₂(x)=5 → x=2⁵=32.'},{title:'Combine logs',body:'log(x)+log(x+3)=1 → log(x(x+3))=1 → x(x+3)=10.'},{title:'Solve resulting equation',body:'x²+3x-10=0 → (x+5)(x-2)=0 → x=2 (reject x=-5).'},{title:'Check domain',body:'Log arguments must be positive. Reject extraneous solutions.'}], explanation:'Always check for extraneous solutions — negative arguments are undefined.', exercises:[{question:'log₃(x)=4. Find x.',answer:'81',hint:'x=3⁴=81.'},{question:'log(x)+log(5)=2. Find x.',answer:'20',hint:'log(5x)=2 → 5x=100.'},{question:'ln(x)=3. Find x.',answer:'e³≈20.09',hint:'x=e³.'}]},
  { id:'exponential-equations', title:'Solving Exponential Equations', grade:'912', gradeLabel:'9–12', subject:'precalculus', tags:['exponential','equation','logarithm','same base','solve'], summary:'Solve exponential equations by matching bases or taking logarithms.', intro:'When bases match, exponents are equal. Otherwise, take the log of both sides.', steps:[{title:'Same base',body:'2^(x+1)=2⁵ → x+1=5 → x=4.'},{title:'Different base: take log',body:'3^x=50 → x=log(50)/log(3)≈3.56.'},{title:'Natural log',body:'e^(2x)=15 → 2x=ln(15) → x≈1.35.'},{title:'Check',body:'Always substitute back to verify.'}], explanation:'Taking log of both sides uses the equivalence: a=b ↔ log(a)=log(b).', exercises:[{question:'5^x=125. Solve.',answer:'x=3',hint:'5³=125.'},{question:'2^(2x)=16. Solve.',answer:'x=2',hint:'2⁴=16 → 2x=4.'},{question:'e^x=7. Solve.',answer:'x=ln7≈1.95',hint:'Take ln of both sides.'}]},
  { id:'arc-radian-measure', title:'Radian Measure', grade:'912', gradeLabel:'9–12', subject:'trigonometry', tags:['radian','degree','convert','arc length','unit circle'], summary:'Convert between degrees and radians and use radians for arc length.', intro:'Radians measure angles as arc length on a unit circle. 180°=π radians.', steps:[{title:'Conversion formula',body:'radians = degrees × π/180. degrees = radians × 180/π.'},{title:'Key values',body:'0°=0, 30°=π/6, 45°=π/4, 60°=π/3, 90°=π/2, 180°=π, 360°=2π.'},{title:'Arc length',body:'s=rθ (θ in radians). r=5, θ=π/3: s=5π/3.'},{title:'Why radians',body:'Many calculus formulas require radians (derivative of sin(x)=cos(x) only when x is in radians).'}], explanation:'Radians make calculus and physics formulas elegant — the "natural" unit of angle.', exercises:[{question:'Convert 150° to radians.',answer:'5π/6',hint:'150×π/180=5π/6.'},{question:'Convert 2π/3 to degrees.',answer:'120°',hint:'(2π/3)(180/π)=120.'},{question:'Arc length: r=8, θ=π/4.',answer:'2π',hint:'s=8×π/4=2π.'}]},
  { id:'piecewise-functions', title:'Piecewise Functions', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['piecewise','function','domain restrictions','graph'], summary:'Evaluate and graph piecewise-defined functions.', intro:'A piecewise function uses different rules for different parts of the domain.', steps:[{title:'Read domain restrictions',body:'f(x) = {x+1 if x<0; x² if x≥0}.'},{title:'Evaluate',body:'f(-3)=(-3)+1=-2 (use first piece since -3<0). f(4)=4²=16.'},{title:'Graph each piece',body:'Graph x+1 for x<0 (open circle at 0). Graph x² for x≥0 (closed circle at 0).'},{title:'Check continuity',body:'Is there a jump at x=0? Left: 0+1=1. Right: 0²=0. Jump discontinuity.'}], explanation:'Piecewise functions model real situations: tax brackets, shipping rates, phone plans.', exercises:[{question:'f(x)={2x, x<1; x+3, x≥1}. Find f(0) and f(5).',answer:'f(0)=0, f(5)=8',hint:'0<1: use 2x. 5≥1: use x+3.'},{question:'Same function. Is it continuous at x=1?',answer:'No: left=2, right=4',hint:'Check both sides.'},{question:'Tax: 10% up to $10000, 20% above. Tax on $15000?',answer:'$2000',hint:'10%×10000+20%×5000=1000+1000.'}]},
  { id:'derivatives-product-quotient', title:'Product and Quotient Rules', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['product rule','quotient rule','derivative','differentiation'], summary:'Differentiate products and quotients of functions.', intro:'The product and quotient rules handle derivatives of combined functions.', steps:[{title:'Product rule',body:'(fg)\'=f\'g+fg\'. Example: (x²)(sin x)\'=2x·sin x+x²cos x.'},{title:'Quotient rule',body:'(f/g)\'=(f\'g-fg\')/g². "Low d-High minus High d-Low over Low squared."'},{title:'Quotient example',body:'(x²)/(x+1): (2x(x+1)-x²(1))/(x+1)²=(x²+2x)/(x+1)².'},{title:'Check with product rule',body:'Rewrite f/g as f·g⁻¹ and use product+chain rule.'}], explanation:'Product rule comes from the limit definition. It is NOT (fg)\'=f\'g\'.', exercises:[{question:'Differentiate x³ sin x.',answer:'3x² sin x + x³ cos x',hint:'Product rule.'},{question:'Differentiate x/(x+2).',answer:'2/(x+2)²',hint:'Quotient rule.'},{question:'Differentiate e^x ln x.',answer:'e^x ln x + e^x/x',hint:'Product rule.'}]},
  { id:'fundamental-theorem-calculus', title:'Fundamental Theorem of Calculus', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['fundamental theorem','calculus','FTC','antiderivative','definite integral'], summary:'Apply both parts of the Fundamental Theorem of Calculus.', intro:'The FTC connects differentiation and integration — the two pillars of calculus.', steps:[{title:'FTC Part 1',body:'d/dx[∫ₐˣ f(t)dt] = f(x). Derivative of an integral recovers the integrand.'},{title:'FTC Part 2',body:'∫ₐᵇ f(x)dx = F(b)-F(a) where F is any antiderivative of f.'},{title:'Evaluate definite integral',body:'∫₁³ x² dx = [x³/3]₁³ = 9-1/3 = 26/3.'},{title:'Net area',body:'Integral gives signed area — negative where f(x)<0.'}], explanation:'Newton and Leibniz discovered this independently. It is arguably the most important theorem in mathematics.', exercises:[{question:'∫₀⁴ (2x+1)dx=?',answer:'20',hint:'[x²+x]₀⁴=16+4-0=20.'},{question:'d/dx[∫₁ˣ √t dt]=?',answer:'√x',hint:'FTC Part 1: the answer is just f(x).'},{question:'∫₀¹ e^x dx=?',answer:'e-1',hint:'[e^x]₀¹=e-1.'}]},
  { id:'statistics-confidence-intervals', title:'Confidence Intervals', grade:'912', gradeLabel:'9–12', subject:'statistics', tags:['confidence interval','margin of error','mean','proportion','95%'], summary:'Construct and interpret confidence intervals for means and proportions.', intro:'A confidence interval gives a range of plausible values for a population parameter.', steps:[{title:'Formula for mean',body:'x̄ ± z*(σ/√n). 95% CI uses z*=1.96.'},{title:'Margin of error',body:'ME = z*(σ/√n). Larger n → smaller ME.'},{title:'Interpret',body:'"We are 95% confident the true mean is between 47.2 and 52.8."'},{title:'For proportions',body:'p̂ ± z*√(p̂(1-p̂)/n).'}], explanation:'95% confidence means the procedure produces an interval containing the true parameter 95% of the time.', exercises:[{question:'n=100, x̄=50, σ=10. 95% CI?',answer:'(48.04, 51.96)',hint:'50±1.96(10/10)=50±1.96.'},{question:'n=400, p̂=0.6. 95% CI?',answer:'≈(0.552, 0.648)',hint:'0.6±1.96√(0.24/400).'},{question:'What happens to the interval width when n is quadrupled?',answer:'It is halved',hint:'ME∝1/√n. √4=2, so ME halved.'}]},
  { id:'hypothesis-testing', title:'Hypothesis Testing', grade:'912', gradeLabel:'9–12', subject:'statistics', tags:['hypothesis test','null hypothesis','p-value','significance','reject'], summary:'Conduct hypothesis tests using the null/alternative hypothesis framework.', intro:'Hypothesis testing uses data to decide whether to reject a claim about a population.', steps:[{title:'State hypotheses',body:'H₀: null hypothesis (no effect). H₁: alternative (claim).'},{title:'Choose significance level',body:'α=0.05 is standard. Reject H₀ if p-value<α.'},{title:'Calculate test statistic',body:'z = (x̄-μ₀)/(σ/√n) for one-sample z-test.'},{title:'p-value',body:'Probability of getting results as extreme as observed, given H₀ is true.'},{title:'Conclusion',body:'p<α: reject H₀. p≥α: fail to reject H₀ (not proof of H₀).'}], explanation:'"Fail to reject" is NOT the same as "accept H₀." Statistical significance ≠ practical significance.', exercises:[{question:'p=0.03, α=0.05. Conclusion?',answer:'Reject H₀',hint:'0.03<0.05.'},{question:'p=0.12, α=0.05. Conclusion?',answer:'Fail to reject H₀',hint:'0.12>0.05.'},{question:'What does p=0.01 mean?',answer:'1% chance of this result if H₀ is true',hint:'p-value is a conditional probability.'}]},
  { id:'riemann-sums', title:'Riemann Sums', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['Riemann sum','area','left right midpoint','approximation','integral'], summary:'Approximate the area under a curve using Riemann sums.', intro:'A Riemann sum approximates a definite integral by summing rectangle areas.', steps:[{title:'Partition interval',body:'Divide [a,b] into n equal subintervals of width Δx=(b-a)/n.'},{title:'Left Riemann sum',body:'Use left endpoint of each subinterval: Σf(xᵢ)Δx.'},{title:'Right Riemann sum',body:'Use right endpoint.'},{title:'Midpoint sum',body:'Use midpoint — usually most accurate.'},{title:'Limit gives exact integral',body:'As n→∞, Riemann sum → definite integral.'}], explanation:'The definite integral is defined as the limit of Riemann sums.', exercises:[{question:'Left Riemann sum for f(x)=x² on [0,2], n=4?',answer:'Δx=0.5. Sum=0+0.25+1+2.25 all ×0.5=1.75',hint:'Points: 0,0.5,1,1.5. f values: 0,0.25,1,2.25.'},{question:'True integral ∫₀² x² dx=?',answer:'8/3≈2.67',hint:'[x³/3]₀².'},{question:'More rectangles make Riemann sum ___ accurate.',answer:'More accurate',hint:'More rectangles → smaller Δx → better approximation.'}]},
  { id:'polar-coordinates', title:'Polar Coordinates', grade:'912', gradeLabel:'9–12', subject:'precalculus', tags:['polar','coordinates','r','theta','convert','Cartesian'], summary:'Represent points using polar coordinates and convert between polar and Cartesian.', intro:'Polar coordinates (r, θ) describe a point by its distance from the origin and angle from the positive x-axis.', steps:[{title:'Read polar coordinates',body:'(r, θ): r=distance, θ=angle (measured counterclockwise from positive x-axis).'},{title:'Convert to Cartesian',body:'x=r cos θ, y=r sin θ.'},{title:'Convert to polar',body:'r=√(x²+y²), θ=arctan(y/x).'},{title:'Example',body:'(4, π/6): x=4cos(π/6)=2√3, y=4sin(π/6)=2.'}], explanation:'Polar coordinates simplify equations of circles, spirals, and rose curves.', exercises:[{question:'Convert (3, π/2) to Cartesian.',answer:'(0, 3)',hint:'3cos(π/2)=0. 3sin(π/2)=3.'},{question:'Convert (3,4) to polar.',answer:'(5, arctan(4/3)≈53.1°)',hint:'r=5, θ=arctan(4/3).'},{question:'Polar equation r=5 describes what shape?',answer:'Circle, radius 5',hint:'r=constant=circle.'}]},
];